#include <stdio.h>

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long N, X;
        scanf("%lld %lld", &N, &X);
        long long groups = N / 3;
        long long rem = N % 3;
        long long cost1 = 2 * X * groups + X * rem;
        long long cost2 = 2 * X * (groups + 1);
        long long ans = (rem == 0) ? cost1 : (cost1 < cost2 ? cost1 : cost2);
        printf("%lld\n", ans);
    }
    return 0;
}

